INSERT INTO public.products (name, slug, short_description, description, price, compare_at_price, stock, images, category_id, is_published, is_featured) VALUES
('SkyGear Pro X1', 'skygear-pro-x1', '4K HDR camera drone with 46-min flight time', 'The Pro X1 is our flagship aerial platform. A 1-inch CMOS sensor captures 5.4K/60 video, obstacle sensing in all directions keeps you safe, and OcuSync 4 delivers a 15 km transmission range.', 1299.00, 1499.00, 12, ARRAY['https://images.unsplash.com/photo-1508614589041-895b88991e8e?auto=format&fit=crop&w=900&q=80'], (SELECT id FROM c WHERE slug='drones'), true, true),
('SkyGear Mini Fold', 'skygear-mini-fold', 'Sub-250g foldable travel drone, 4K/30', 'Weighing less than 249 g, the Mini Fold slips into a jacket pocket yet shoots stabilized 4K/30 footage with a 3-axis gimbal. Perfect for travel creators.', 549.00, NULL, 30, ARRAY['https://images.unsplash.com/photo-1579829366248-204fe8413f31?auto=format&fit=crop&w=900&q=80'], (SELECT id FROM c WHERE slug='drones'), true, true),
('SkyGear FPV Racer', 'skygear-fpv-racer', 'Carbon-frame FPV drone, 140 km/h top speed', 'Purpose-built for freestyle and racing pilots. Carbon fiber frame, brushless 2306 motors, and analog/digital HD video options for a low-latency FPV experience.', 799.00, 899.00, 8, ARRAY['https://images.unsplash.com/photo-1524143983365-2aa047986b7b?auto=format&fit=crop&w=900&q=80'], (SELECT id FROM c WHERE slug='drones'), true, true),
('SkyGear Cinema 8K', 'skygear-cinema-8k', 'Full-frame cinema drone with ProRes RAW', 'Built for professional cinematographers: dual-battery redundancy, full-frame 8K sensor, ProRes RAW, and a 55-minute flight time.', 4499.00, NULL, 4, ARRAY['https://images.unsplash.com/photo-1473968512647-3e447244af8f?auto=format&fit=crop&w=900&q=80'], (SELECT id FROM c WHERE slug='drones'), true, true),
('Intelligent Flight Battery', 'intelligent-flight-battery', 'Swap batteries in under 30 seconds', '5000 mAh LiPo pack tuned for the Pro X1. Delivers up to 46 minutes of flight and includes onboard cell balancing and low-temp performance.', 189.00, NULL, 40, ARRAY['https://images.unsplash.com/photo-1609091839311-dea83be1f51a?auto=format&fit=crop&w=900&q=80'], (SELECT id FROM c WHERE slug='batteries'), true, false),
('Low-Noise Propellers (4-pack)', 'low-noise-propellers', 'Quieter flight, longer endurance', 'CNC-balanced propellers reduce sound signature by up to 4 dB while extending flight time by up to 5%.', 24.00, NULL, 120, ARRAY['https://images.unsplash.com/photo-1581092160562-40aa08e78837?auto=format&fit=crop&w=900&q=80'], (SELECT id FROM c WHERE slug='accessories'), true, false),
('3-Axis Handheld Gimbal', 'handheld-gimbal', 'Rock-steady footage from any camera', 'Repurpose your drone camera or mirrorless body with our brushless 3-axis stabilizer. 12-hour battery, ARRI-style side handle.', 349.00, 399.00, 15, ARRAY['https://images.unsplash.com/photo-1516035069371-29a1b244ccaf?auto=format&fit=crop&w=900&q=80'], (SELECT id FROM c WHERE slug='gimbals'), true, true),
('Smart Controller with 7" Display', 'smart-controller', '1000-nit sunlight-readable screen', 'No more phone mounting. Built-in 1000-nit display, HDMI out, and a customizable HD downlink up to 15 km.', 729.00, NULL, 10, ARRAY['https://images.unsplash.com/photo-1558618666-fcd25c85cd64?auto=format&fit=crop&w=900&q=80'], (SELECT id FROM c WHERE slug='accessories'), true, false),
('Hardshell Travel Case', 'hardshell-case', 'IP67 waterproof, TSA carry-on friendly', 'Custom-cut foam holds one drone, six batteries, controller, and cables. Airline carry-on compliant.', 129.00, NULL, 25, ARRAY['https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?auto=format&fit=crop&w=900&q=80'], (SELECT id FROM c WHERE slug='accessories'), true, false),
('ND Filter Set (6-pack)', 'nd-filter-set', 'ND4/8/16/32/64/PL for perfect exposure', 'Multi-coated Schott glass filters that thread onto your drone gimbal camera. Includes travel case.', 89.00, 109.00, 60, ARRAY['https://images.unsplash.com/photo-1511285560929-80b456fea0bc?auto=format&fit=crop&w=900&q=80'], (SELECT id FROM c WHERE slug='accessories'), true, false)
